#include "qp/features/rolling_mean.hpp"
namespace qp::features { RollingMean::RollingMean(std::size_t w,std::string n): name_(n.empty()?"rolling_mean_"+std::to_string(w):std::move(n)), capacity_(w){} std::string_view RollingMean::name() const noexcept{return name_;} Result<std::optional<FeatureValue>> RollingMean::update(const data::MarketData& d){ const auto& sym=data::symbol(d); auto [it,_]=windows_.try_emplace(sym, capacity_); it->second.push(data::reference_price(d)); if(!it->second.full()) return Ok(std::optional<FeatureValue>{}); return Ok(std::optional<FeatureValue>{FeatureValue{data::timestamp(d), sym, name_, it->second.mean()}}); } void RollingMean::reset(){ windows_.clear(); } }
